{
  "sentences": [
    {
      "text": "請你走進來。",
      "pinyin": "Qǐng nǐ zǒu jìnlái.",
      "pinyin_numeric": "qing3 ni3 zou3 jin4lai2",
      "translation_en": "Please walk in.",
      "translation_ko": "안으로 걸어 들어오세요."
    },
    {
      "text": "他跑出去了。",
      "pinyin": "Tā pǎo chūqù le.",
      "pinyin_numeric": "ta1 pao3 chu1qu4 le0",
      "translation_en": "He ran out.",
      "translation_ko": "그가 뛰어 나갔어요."
    },
    {
      "text": "貓從窗戶跳下來。",
      "pinyin": "Māo cóng chuānghù tiào xiàlái.",
      "pinyin_numeric": "mao1 cong2 chuang1hu4 tiao4 xia4lai2",
      "translation_en": "The cat jumped down from the window.",
      "translation_ko": "고양이가 창문에서 뛰어내렸어요."
    },
    {
      "text": "我們把書拿上去。",
      "pinyin": "Wǒmen bǎ shū ná shàngqù.",
      "pinyin_numeric": "wo3men0 ba3 shu1 na2 shang4qu4",
      "translation_en": "We take the book up.",
      "translation_ko": "우리가 책을 위로 가져갈게요."
    },
    {
      "text": "請你帶下來。",
      "pinyin": "Qǐng nǐ dài xiàlái.",
      "pinyin_numeric": "qing3 ni3 dai4 xia4lai2",
      "translation_en": "Please bring it down.",
      "translation_ko": "아래로 가져와 주세요."
    },
    {
      "text": "他從樓上走下來。",
      "pinyin": "Tā cóng lóushàng zǒu xiàlái.",
      "pinyin_numeric": "ta1 cong2 lou2shang4 zou3 xia4lai2",
      "translation_en": "He walked down from upstairs.",
      "translation_ko": "그가 위층에서 걸어 내려왔어요."
    },
    {
      "text": "鳥飛進來了。",
      "pinyin": "Niǎo fēi jìnlái le.",
      "pinyin_numeric": "niao3 fei1 jin4lai2 le0",
      "translation_en": "The bird flew in.",
      "translation_ko": "새가 날아 들어왔어요."
    },
    {
      "text": "請你把東西放進去。",
      "pinyin": "Qǐng nǐ bǎ dōngxī fàng jìnqù.",
      "pinyin_numeric": "qing3 ni3 ba3 dong1xi1 fang4 jin4qu4",
      "translation_en": "Please put the things in.",
      "translation_ko": "물건을 안에 넣어 주세요."
    },
    {
      "text": "他從車子裡出來。",
      "pinyin": "Tā cóng chēzi lǐ chūlái.",
      "pinyin_numeric": "ta1 cong2 che1zi0 li3 chu1lai2",
      "translation_en": "He came out of the car.",
      "translation_ko": "그가 차 안에서 나왔어요."
    },
    {
      "text": "我們一起爬上去。",
      "pinyin": "Wǒmen yīqǐ pá shàngqù.",
      "pinyin_numeric": "wo3men0 yi1qi3 pa2 shang4qu4",
      "translation_en": "Let's climb up together.",
      "translation_ko": "우리 함께 올라가요."
    }
  ]
}
